{"command": "curl -s "https://api.thingspeak.com/channels/2785218/feeds.json?results=288" | python3 -c "
import json, sys
data = json.load(sys.stdin)
feeds = data['feeds']
temps, hums, soils, luxs = [], [], [], []
for f in feeds:
    if f.get('field1'): temps.append(float(f['field1']))
    if f.get('field2'): hums.append(float(f['field2']))
    if f.get('field3'): luxs.append(float(f['field3']))
    if f.get('field4'): soils.append(float(f['field4']))

def stats(lst, name):
    if not lst: return f'{name}: No data'
    return f'{name}: avg={sum(lst)/len(lst):.1f} min={min(lst):.1f} max={max(lst):.1f} count={len(lst)}'

print(stats(temps,'TEMP'))
print(stats(hums,'HUM'))
print(stats(soils,'SOIL'))
print(stats(luxs,'LUX'))
"
